2936           InstructionCost MulCost = Mul->computeCost(VF, Ctx);
2937           InstructionCost RedCost = Red->computeCost(VF, Ctx);
2938           InstructionCost ExtCost = 0;
2939           if (Ext0)
2940             ExtCost += Ext0->computeCost(VF, Ctx);
2941           if (Ext1)
2942             ExtCost += Ext1->computeCost(VF, Ctx);
2943           if (OuterExt)
