235   case Instruction::ExtractValue:
236     return R->getUnderlyingInstr()->getType();
237   case Instruction::Freeze:
238   case Instruction::FNeg:
239   case Instruction::GetElementPtr:
240     return inferScalarType(R->getOperand(0));
241   case Instruction::Load:
242     return cast<LoadInst>(R->getUnderlyingInstr())->getType();
243   case Instruction::Store:
244     // FIXME: VPReplicateRecipes with store opcodes still define a result
245     // VPValue, so we need to handle them here. Remove the code here once this
246     // is modeled accurately in VPlan.
247     return Type::getVoidTy(Ctx);
248   default:
249     break;
250   }
251   // Type inference not implemented for opcode.
252   LLVM_DEBUG({
253     dbgs() << "LV: Found unhandled opcode for: ";
254     R->getVPSingleValue()->dump();
255   });
256   llvm_unreachable("Unhandled opcode");
257 }
258 
259 Type *VPTypeAnalysis::inferScalarType(const VPValue *V) {
260   if (Type *CachedTy = CachedTypes.lookup(V))
261     return CachedTy;
262 
263   if (V->isLiveIn()) {
264     if (auto *IRValue = V->getLiveInIRValue())
265       return IRValue->getType();
266     // All VPValues without any underlying IR value (like the vector trip count
267     // or the backedge-taken count) have the same type as the canonical IV.
268     return CanonicalIVTy;
269   }
270 
271   Type *ResultTy =
272       TypeSwitch<const VPRecipeBase *, Type *>(V->getDefiningRecipe())
273           .Case<VPActiveLaneMaskPHIRecipe, VPCanonicalIVPHIRecipe,
274                 VPFirstOrderRecurrencePHIRecipe, VPReductionPHIRecipe,
275                 VPWidenPointerInductionRecipe, VPEVLBasedIVPHIRecipe>(
276               [this](const auto *R) {
277                 // Handle header phi recipes, except VPWidenIntOrFpInduction
278                 // which needs special handling due it being possibly truncated.
279                 // TODO: consider inferring/caching type of siblings, e.g.,
280                 // backedge value, here and in cases below.
281                 return inferScalarType(R->getStartValue());
282               })
283           .Case<VPWidenIntOrFpInductionRecipe, VPDerivedIVRecipe>(
284               [](const auto *R) { return R->getScalarType(); })
285           .Case<VPReductionRecipe, VPPredInstPHIRecipe, VPWidenPHIRecipe,
286                 VPScalarIVStepsRecipe, VPWidenGEPRecipe, VPVectorPointerRecipe,
287                 VPVectorEndPointerRecipe, VPWidenCanonicalIVRecipe,
288                 VPPartialReductionRecipe>([this](const VPRecipeBase *R) {
289             return inferScalarType(R->getOperand(0));
290           })
291           // VPInstructionWithType must be handled before VPInstruction.
292           .Case<VPInstructionWithType, VPWidenIntrinsicRecipe,
293                 VPWidenCastRecipe>(
294               [](const auto *R) { return R->getResultType(); })
295           .Case<VPBlendRecipe, VPInstruction, VPWidenRecipe, VPReplicateRecipe,
296                 VPWidenCallRecipe, VPWidenMemoryRecipe, VPWidenSelectRecipe>(
297               [this](const auto *R) { return inferScalarTypeForRecipe(R); })
298           .Case<VPInterleaveRecipe>([V](const VPInterleaveRecipe *R) {
299             // TODO: Use info from interleave group.
300             return V->getUnderlyingValue()->getType();
301           })
302           .Case<VPExpandSCEVRecipe>([](const VPExpandSCEVRecipe *R) {
303             return R->getSCEV()->getType();
304           })
305           .Case<VPReductionRecipe>([this](const auto *R) {
306             return inferScalarType(R->getChainOp());
307           })
308           .Case<VPExpressionRecipe>([this](const auto *R) {
309             return inferScalarType(R->getOperandOfResultType());
310           });
311 
312   assert(ResultTy && "could not infer type for the given VPValue");
313   CachedTypes[V] = ResultTy;
314   return ResultTy;
315 }
316 
317 void llvm::collectEphemeralRecipesForVPlan(
318     VPlan &Plan, DenseSet<VPRecipeBase *> &EphRecipes) {
319   // First, collect seed recipes which are operands of assumes.
320   SmallVector<VPRecipeBase *> Worklist;
321   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
322            vp_depth_first_deep(Plan.getVectorLoopRegion()->getEntry()))) {
323     for (VPRecipeBase &R : *VPBB) {
324       auto *RepR = dyn_cast<VPReplicateRecipe>(&R);
325       if (!RepR || !match(RepR->getUnderlyingInstr(),
326                           PatternMatch::m_Intrinsic<Intrinsic::assume>()))
327         continue;
328       Worklist.push_back(RepR);
329       EphRecipes.insert(RepR);
330     }
331   }
332 
333   // Process operands of candidates in worklist and add them to the set of
334   // ephemeral recipes, if they don't have side-effects and are only used by
335   // other ephemeral recipes.
336   while (!Worklist.empty()) {
337     VPRecipeBase *Cur = Worklist.pop_back_val();
338     for (VPValue *Op : Cur->operands()) {
339       auto *OpR = Op->getDefiningRecipe();
340       if (!OpR || OpR->mayHaveSideEffects() || EphRecipes.contains(OpR))
341         continue;
342       if (any_of(Op->users(), [EphRecipes](VPUser *U) {
343             auto *UR = dyn_cast<VPRecipeBase>(U);
344             return !UR || !EphRecipes.contains(UR);
345           }))
346         continue;
347       EphRecipes.insert(OpR);
348       Worklist.push_back(OpR);
349     }
